package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrintReturnsCSVPrinter() throws IOException {
        Appendable mockAppendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(mockAppendable);
        assertNotNull(printer);
        assertEquals(mockAppendable, getAppendableFromPrinter(printer));
    }

    @Test
    public void testPrintWithNullAppendableThrowsException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.print(null);
        });
    }

    // Helper method to access the private 'out' field of CSVPrinter via reflection
    private Appendable getAppendableFromPrinter(CSVPrinter printer) {
        try {
            Field field = CSVPrinter.class.getDeclaredField("out");
            field.setAccessible(true);
            return (Appendable) field.get(printer);
        } catch (Exception e) {
            fail("Reflection failed to get 'out' field from CSVPrinter: " + e.getMessage());
            return null;
        }
    }
}
